// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: { day: string; icon: string; high: number; low: number }[]; // 5-day forecast array
}

function useComponent(props: Props) {
  const getWeatherEmoji = useCallback((condition: string) => {
    const c = condition.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('snow') || c.includes('ice')) return '❄️';
    if (c.includes('storm') || c.includes('thunder')) return '⛈️';
    if (c.includes('mist') || c.includes('fog') || c.includes('haze')) return '🌫️';
    return '⛅';
  }, []);

  const formattedTemp = useMemo(() => {
    return `${Math.round(props.temperature)}°${props.unit}`;
  }, [props.temperature, props.unit]);

  return {
    getWeatherEmoji,
    formattedTemp
  };
}

export default function Component(props: Props) {
  const { getWeatherEmoji, formattedTemp } = useComponent(props);

  return (
    <Card shadow="md" padding={24} radius="xl" border={true}>
      <Stack gap={24}>
        {/* City and Condition Header */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={4}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {props.city}
            </Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
            </Text>
          </Stack>
          <Badge variant="primary" size="lg">{props.condition}</Badge>
        </Stack>

        {/* Main Temperature Display */}
        <Stack direction="horizontal" justify="between" align="center">
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-primary-600, #0284c7)"
            style={{ fontSize: 'var(--ggui-font-size-4xl, 48px)', lineHeight: 1 }}
          >
            {formattedTemp}
          </Text>
          <Box padding={16} borderRadius="var(--ggui-shape-radius-full, 9999px)" background="var(--ggui-color-primary-50, #f0f9ff)">
            <Text style={{ fontSize: '48px', lineHeight: 1 }}>
              {getWeatherEmoji(props.condition)}
            </Text>
          </Box>
        </Stack>

        {/* Secondary Metrics */}
        <Stack direction="horizontal" justify="around" align="center" style={{ background: 'var(--ggui-color-surfaceVariant, #f4f4f5)', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', padding: '16px' }}>
          <Stack gap={4} align="center">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">HUMIDITY</Text>
            <Text variant="bodyLarge" weight="semibold">{props.humidity}%</Text>
          </Stack>
          <Divider orientation="vertical" margin={12} color="var(--ggui-color-outline, #d4d4d8)" />
          <Stack gap={4} align="center">
            <Text variant="overline" color="var(--ggui-color-onSurfaceVariant, #52525b)">WIND</Text>
            <Text variant="bodyLarge" weight="semibold">{props.windSpeed} km/h</Text>
          </Stack>
        </Stack>

        {/* 5-Day Forecast Strip */}
        <Stack gap={12}>
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">5-DAY FORECAST</Text>
          <Stack direction="horizontal" justify="between" align="center">
            {props.forecast.map((item, index) => (
              <Stack key={index} gap={8} align="center" style={{ flex: 1 }}>
                <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.day}</Text>
                <Text style={{ fontSize: '24px' }}>{getWeatherEmoji(item.icon)}</Text>
                <Stack direction="horizontal" gap={4}>
                  <Text variant="caption" weight="bold">{item.high}°</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{item.low}°</Text>
                </Stack>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit?: (data: Record<string, unknown>) => void; // Action: Submit Survey
}

function useComponent(props: Props) {
  const handleSubmit = useCallback((data: Record<string, unknown>) => {
    if (props.onSubmit) {
      props.onSubmit(data);
    }
  }, [props.onSubmit]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: '',
    features: [] as string[],
    comments: ''
  });

  const isEmailValid = useCallback((email: string) => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return re.test(email);
  }, []);

  const isStepValid = useMemo(() => {
    switch (step) {
      case 1:
        return !!formData.name.trim() && isEmailValid(formData.email);
      case 2:
        return !!formData.satisfaction;
      case 3:
        return true; // Interests are optional
      case 4:
        return formData.comments.length <= 500;
      default:
        return true;
    }
  }, [step, formData, isEmailValid]);

  const totalSteps = 5; // 4 input steps + 1 review step

  const handleNext = useCallback(() => {
    setStep(s => Math.min(s + 1, totalSteps));
  }, [totalSteps]);

  const handleBack = useCallback(() => {
    setStep(s => Math.max(s - 1, 1));
  }, []);

  const satisfactionOptions = useMemo(() => 
    props.satisfactionLabels.map((label, i) => ({
      value: String(i + 1),
      label: label
    })), [props.satisfactionLabels]);

  return {
    step,
    formData,
    setFormData,
    isStepValid,
    totalSteps,
    handleNext,
    handleBack,
    handleSubmit,
    satisfactionOptions,
    isEmailValid
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Card padding={32} shadow="md" radius="xl">
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={2}>Customer Survey</Heading>
            <Progress value={(state.step / state.totalSteps) * 100} variant="default" size="md" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Step {state.step} of {state.totalSteps}
            </Text>
          </Stack>

          <Box style={{ minHeight: '320px' }}>
            {state.step === 1 && (
              <Stack gap={16}>
                <Heading level={4}>Contact Information</Heading>
                <Input label="Name"
                  required
                  placeholder="Enter your full name"
                  value={state.formData.name}
                  onChange={(val) => state.setFormData(prev => ({ ...prev, name: val }))}
                />
                <Input label="Email"
                  type="email"
                  required
                  placeholder="you@example.com"
                  value={state.formData.email}
                  onChange={(val) => state.setFormData(prev => ({ ...prev, email: val }))}
                  error={state.formData.email && !state.isEmailValid(state.formData.email) ? "Please enter a valid email address" : undefined}
                />
              </Stack>
            )}

            {state.step === 2 && (
              <Stack gap={16}>
                <Heading level={4}>Overall Satisfaction</Heading>
                <RadioGroup
                  label="How satisfied are you with our service?"
                  options={state.satisfactionOptions}
                  value={state.formData.satisfaction}
                  onChange={(val) => state.setFormData(prev => ({ ...prev, satisfaction: val }))}
                />
              </Stack>
            )}

            {state.step === 3 && (
              <Stack gap={16}>
                <Heading level={4}>Feature Interests</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  Select all features that interest you (optional)
                </Text>
                <Stack gap={12}>
                  {props.featureOptions.map(option => (
                    <Checkbox
                      key={option}
                      label={option}
                      checked={state.formData.features.includes(option)}
                      onChange={(checked) => {
                        state.setFormData(prev => ({
                          ...prev,
                          features: checked 
                            ? [...prev.features, option] 
                            : prev.features.filter(f => f !== option)
                        }));
                      }}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {state.step === 4 && (
              <Stack gap={16}>
                <Heading level={4}>Additional Comments</Heading>
                <TextArea
                  label="What else would you like us to know?"
                  placeholder="Share your thoughts..."
                  value={state.formData.comments}
                  onChange={(val) => state.setFormData(prev => ({ ...prev, comments: val }))}
                  maxLength={500}
                  showCount
                  rows={6}
                />
              </Stack>
            )}

            {state.step === 5 && (
              <Stack gap={16}>
                <Heading level={4}>Final Review</Heading>
                <Alert variant="info" title="Ready to submit">
                  Please review your information before completing the survey.
                </Alert>
                <Stack gap={12} style={{ padding: '16px', backgroundColor: 'var(--ggui-color-surfaceVariant)', borderRadius: 'var(--ggui-shape-radius-md)' }}>
                  <Stack gap={4}>
                    <Text variant="label">Name & Email</Text>
                    <Text variant="bodySmall">{state.formData.name} ({state.formData.email})</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label">Satisfaction</Text>
                    <Text variant="bodySmall">{props.satisfactionLabels[Number(state.formData.satisfaction) - 1]}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label">Interests</Text>
                    <Text variant="bodySmall">{state.formData.features.join(', ') || 'No features selected'}</Text>
                  </Stack>
                  <Stack gap={4}>
                    <Text variant="label">Comments</Text>
                    <Text variant="bodySmall" style={{ fontStyle: state.formData.comments ? 'normal' : 'italic' }}>
                      {state.formData.comments || 'No comments provided'}
                    </Text>
                  </Stack>
                </Stack>
              </Stack>
            )}
          </Box>

          <Divider margin={8} />

          <Stack direction="horizontal" justify="between" align="center">
            <Button
              variant="ghost"
              onClick={state.handleBack}
              disabled={state.step === 1}
              leftIcon={<Icon name="chevron-left" size={16} />}
            >
              Back
            </Button>

            {state.step < state.totalSteps ? (
              <Button
                variant="primary"
                onClick={state.handleNext}
                disabled={!state.isStepValid}
                rightIcon={<Icon name="chevron-right" size={16} />}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                onClick={() => state.handleSubmit(state.formData)}
                leftIcon={<Icon name="check" size={16} />}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[]; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: { id: string; name: string }[]; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    if (props.onTaskUpdate) {
      props.onTaskUpdate(data);
    }
  }, [props.onTaskUpdate]);

  const [localTasks, setLocalTasks] = useState(props.tasks);
  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  useEffect(() => {
    setLocalTasks(props.tasks);
  }, [props.tasks]);

  const stats = useMemo(() => {
    const total = localTasks.length;
    const completed = localTasks.filter(t => t.column === 'done').length;
    return { total, completed };
  }, [localTasks]);

  const moveTask = (taskId: string, targetColumn: string) => {
    const updated = localTasks.map(t => 
      t.id === taskId ? { ...t, column: targetColumn } : t
    );
    setLocalTasks(updated);
    handleTaskUpdate({ action: 'move', taskId, targetColumn });
  };

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: `task-${Date.now()}`,
      title: newTaskTitle.trim(),
      priority: newTaskPriority,
      assignee: 'JD', // Default for demo
      column: columnId,
      dueDate: ''
    };
    const updated = [...localTasks, newTask];
    setLocalTasks(updated);
    setAddingToColumn(null);
    setNewTaskTitle('');
    handleTaskUpdate({ action: 'create', task: newTask });
  };

  const handleEditTask = (taskId: string) => {
    if (!editTitle.trim()) {
      setEditingTaskId(null);
      return;
    }
    const updated = localTasks.map(t => 
      t.id === taskId ? { ...t, title: editTitle.trim() } : t
    );
    setLocalTasks(updated);
    setEditingTaskId(null);
    handleTaskUpdate({ action: 'edit', taskId, title: editTitle.trim() });
  };

  const getPriorityVariant = (priority: string): "info" | "warning" | "error" | "default" => {
    switch (priority.toLowerCase()) {
      case 'low': return 'info';
      case 'medium': return 'warning';
      case 'high': return 'error';
      default: return 'default';
    }
  };

  return {
    localTasks,
    stats,
    addingToColumn,
    setAddingToColumn,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    editingTaskId,
    setEditingTaskId,
    editTitle,
    setEditTitle,
    moveTask,
    handleAddTask,
    handleEditTask,
    getPriorityVariant,
    columns: props.columns,
  };
}

export default function Component(props: Props): JSX.Element {
  const state = useComponent(props);

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card padding={16} shadow="sm" border>
          <Stack direction="horizontal" justify="between" align="center" wrap>
            <Stack direction="horizontal" gap={16} align="center">
              <Heading level={2}>Kanban Board</Heading>
              <Divider orientation="vertical" margin={8} />
              <Stack direction="horizontal" gap={8} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Total Tasks:</Text>
                <Badge variant="info" pill={false}>{state.stats.total}</Badge>
              </Stack>
              <Stack direction="horizontal" gap={8} align="center">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Completed:</Text>
                <Badge variant="success" pill={false}>{state.stats.completed}</Badge>
              </Stack>
            </Stack>
            <Box style={{ width: '200px' }}>
              <Progress 
                value={state.stats.total > 0 ? (state.stats.completed / state.stats.total) * 100 : 0} 
                size="sm" 
                variant="success" 
              />
            </Box>
          </Stack>
        </Card>

        {/* Columns Grid */}
        <Stack direction="horizontal" gap={24} align="start" style={{ overflowX: 'auto', minHeight: 'calc(100vh - 240px)', paddingBottom: '16px' }}>
          {state.columns.map(column => {
            const columnTasks = state.localTasks.filter(t => t.column === column.id);

            return (
              <Box 
                key={column.id}
                style={{ flex: '1 0 320px' }}
                background="var(--ggui-color-surfaceVariant, #f4f4f5)"
                borderRadius="var(--ggui-shape-radius-lg, 12px)"
                padding="var(--ggui-spacing-4, 16px)"
              >
                <Stack gap={16}>
                  {/* Column Header */}
                  <Stack direction="horizontal" justify="between" align="center">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="secondary" pill>{columnTasks.length}</Badge>
                  </Stack>

                  {/* Task List */}
                  <Stack gap={12}>
                    {columnTasks.map(task => (
                      <Card key={task.id} padding={12} shadow="sm" radius="md">
                        <Stack gap={12}>
                          {state.editingTaskId === task.id ? (
                            <Stack gap={8}>
                              <Input 
                                label="Edit Task Title"
                                value={state.editTitle} 
                                onChange={state.setEditTitle} 
                                autoFocus
                              />
                              <Stack direction="horizontal" gap={4}>
                                <Button size="xs" onClick={() => state.handleEditTask(task.id)}>Save</Button>
                                <Button size="xs" variant="ghost" onClick={() => state.setEditingTaskId(null)}>Cancel</Button>
                              </Stack>
                            </Stack>
                          ) : (
                            <Stack direction="horizontal" justify="between" align="start">
                              <Box 
                                style={{ cursor: 'pointer', flex: 1 }}
                                onDoubleClick={() => {
                                  state.setEditingTaskId(task.id);
                                  state.setEditTitle(task.title);
                                }}
                              >
                                <Text weight="medium">{task.title}</Text>
                              </Box>
                              <Button 
                                variant="ghost" 
                                size="xs" 
                                onClick={() => {
                                  state.setEditingTaskId(task.id);
                                  state.setEditTitle(task.title);
                                }}
                              >
                                <Icon name="settings" size={14} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                              </Button>
                            </Stack>
                          )}

                          <Stack direction="horizontal" justify="between" align="center">
                            <Badge variant={state.getPriorityVariant(task.priority)} size="sm">
                              {task.priority}
                            </Badge>
                            <Avatar name={task.assignee} size="xs" />
                          </Stack>

                          {task.dueDate && (
                            <Stack direction="horizontal" gap={4} align="center">
                              <Box style={{ opacity: 0.6 }}>
                                <Icon name="menu" size={12} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                              </Box>
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                                {task.dueDate}
                              </Text>
                            </Stack>
                          )}

                          <Divider margin={4} />

                          <Select
                            size="sm"
                            value={task.column}
                            onChange={(val) => state.moveTask(task.id, val)}
                            options={state.columns.map(c => ({ value: c.id, label: `Move to ${c.name}` }))}
                          />
                        </Stack>
                      </Card>
                    ))}

                    {/* Add Task Form */}
                    {state.addingToColumn === column.id ? (
                      <Card padding={12} shadow="sm" border>
                        <Stack gap={12}>
                          <Input 
                            label="Task Title" 
                            placeholder="What needs to be done?" 
                            value={state.newTaskTitle} 
                            onChange={state.setNewTaskTitle} 
                            autoFocus 
                          />
                          <Select
                            label="Priority"
                            value={state.newTaskPriority}
                            onChange={state.setNewTaskPriority}
                            options={[
                              { value: 'low', label: 'Low' },
                              { value: 'medium', label: 'Medium' },
                              { value: 'high', label: 'High' }
                            ]}
                          />
                          <Stack direction="horizontal" gap={8} justify="end">
                            <Button 
                              variant="ghost" 
                              size="sm" 
                              onClick={() => {
                                state.setAddingToColumn(null);
                                state.setNewTaskTitle('');
                              }}
                            >
                              Cancel
                            </Button>
                            <Button 
                              variant="primary" 
                              size="sm" 
                              onClick={() => state.handleAddTask(column.id)}
                              disabled={!state.newTaskTitle.trim()}
                            >
                              Add
                            </Button>
                          </Stack>
                        </Stack>
                      </Card>
                    ) : (
                      <Button 
                        variant="ghost" 
                        fullWidth 
                        leftIcon={<Icon name="plus" size={16} />}
                        onClick={() => state.setAddingToColumn(column.id)}
                      >
                        Add Task
                      </Button>
                    )}
                  </Stack>
                </Stack>
              </Box>
            );
          })}
        </Stack>
      </Stack>
    </Container>
  );
}

// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: { atomicNumber: number; symbol: string; name: string; atomicWeight: number; category: string; row: number; col: number }[]; // Full periodic table element data
}

function useComponent(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const q = searchQuery.toLowerCase().trim();
    if (!q) return props.elements;
    return props.elements.filter(e =>
      e.name.toLowerCase().includes(q) ||
      e.symbol.toLowerCase().includes(q)
    );
  }, [props.elements, searchQuery]);

  const categories = useMemo(() => {
    const set = new Set(props.elements.map(e => e.category));
    return Array.from(set).sort();
  }, [props.elements]);

  const getCategoryStyles = useCallback((category: string) => {
    const cat = category.toLowerCase();
    if (cat.includes('noble gas')) 
      return { bg: 'var(--ggui-color-primary-100, #e0f2fe)', color: 'var(--ggui-color-primary-700, #0369a1)', border: 'var(--ggui-color-primary-300, #7dd3fc)' };
    if (cat.includes('halogen') || cat.includes('reactive nonmetal')) 
      return { bg: 'var(--ggui-color-success-100, #dcfce7)', color: 'var(--ggui-color-success-700, #15803d)', border: 'var(--ggui-color-success-300, #86efac)' };
    if (cat.includes('alkali metal')) 
      return { bg: 'var(--ggui-color-error-100, #fee2e2)', color: 'var(--ggui-color-error-700, #b91c1c)', border: 'var(--ggui-color-error-300, #fca5a5)' };
    if (cat.includes('alkaline earth')) 
      return { bg: 'var(--ggui-color-warning-100, #fef3c7)', color: 'var(--ggui-color-warning-700, #b45309)', border: 'var(--ggui-color-warning-300, #fcd34d)' };
    if (cat.includes('metalloid')) 
      return { bg: 'var(--ggui-color-info-100, #cffafe)', color: 'var(--ggui-color-info-700, #0e7490)', border: 'var(--ggui-color-info-300, #67e8f9)' };
    if (cat.includes('post-transition')) 
      return { bg: 'var(--ggui-color-primary-50, #f0f9ff)', color: 'var(--ggui-color-primary-600, #0284c7)', border: 'var(--ggui-color-primary-200, #bae6fd)' };
    if (cat.includes('transition metal')) 
      return { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: 'var(--ggui-color-onSurfaceVariant, #52525b)', border: 'var(--ggui-color-outline, #d4d4d8)' };
    if (cat.includes('lanthanide') || cat.includes('actinide')) 
      return { bg: 'var(--ggui-color-container, #ede9fe)', color: 'var(--ggui-color-onContainer, #4c1d95)', border: 'var(--ggui-color-outline, #d4d4d8)' };

    return { bg: 'var(--ggui-color-surface, #fafafa)', color: 'var(--ggui-color-onSurface, #18181b)', border: 'var(--ggui-color-outlineVariant, #e4e4e7)' };
  }, []);

  return {
    searchQuery,
    setSearchQuery,
    selectedElement,
    setSelectedElement,
    filteredElements,
    categories,
    getCategoryStyles
  };
}

