// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: unknown[]; reviews: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stockStatus = useMemo(() => {
    if (props.product.stock <= 0) return { label: 'Out of Stock', variant: 'error' as const };
    if (props.product.stock < 10) return { label: 'Low Stock', variant: 'warning' as const };
    return { label: 'In Stock', variant: 'success' as const };
  }, [props.product.stock]);

  const handleIncrement = useCallback(() => {
    setQuantity(prev => Math.min(prev + 1, props.product.stock));
  }, [props.product.stock]);

  const handleDecrement = useCallback(() => {
    setQuantity(prev => Math.max(prev - 1, 1));
  }, []);

  const formattedPrice = useMemo(() => {
    return `${props.product.currency}${props.product.price.toFixed(2)}`;
  }, [props.product.currency, props.product.price]);

  const addToCart = useCallback(() => {
    handleAddToCart({ productId: props.product.id, quantity });
  }, [handleAddToCart, props.product.id, quantity]);

  return {
    quantity,
    activeTab,
    setActiveTab,
    stockStatus,
    handleIncrement,
    handleDecrement,
    formattedPrice,
    addToCart
  };
}

