import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: { sender: string; text: string; timestamp: string }[]; // Array of messages with sender name, text, and ISO timestamp
  onSendMessage?: (data: Record<string, unknown>) => void; // Action: Send Message
}

function useComponent(props: Props) {
  const [text, setText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const handleSendMessage = useCallback((data: Record<string, unknown>) => {
    props.onSendMessage?.(data);
  }, [props.onSendMessage]);

  const onSend = useCallback(() => {
    const trimmed = text.trim();
    if (trimmed) {
      handleSendMessage({
        text: trimmed,
        timestamp: new Date().toISOString()
      });
      setText('');
    }
  }, [text, handleSendMessage]);

  const scrollToBottom = useCallback(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [props.messages, scrollToBottom]);

  return {
    text,
    setText,
    onSend,
    scrollRef
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <div 
      style={{ 
        display: 'flex', 
        flexDirection: 'column',
        height: '600px', 
        maxWidth: '100%',
        overflow: 'hidden' 
      }}
    >
      {/* Header */}
      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Stack direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
            <Heading level={4}>{props.title}</Heading>
            <Badge variant="primary" pill>{props.participantCount} Participants</Badge>
          </Stack>
        </Stack>
      </Box>

      {/* Message List */}
      <div 
        ref={state.scrollRef}
        style={{ 
          flex: 1, 
          overflowY: 'auto',
          padding: 'var(--ggui-spacing-4, 16px)',
          background: 'var(--ggui-color-surface, #fafafa)'
        }}
      >
        <Stack gap="var(--ggui-spacing-4, 16px)">
          {props.messages.map((msg, i) => {
            const isMe = msg.sender === props.currentUser;
            const isFollowUp = i > 0 && props.messages[i - 1].sender === msg.sender;

            return (
              <Stack key={i} align={isMe ? 'end' : 'start'} gap={4} style={{ marginTop: isFollowUp ? '-8px' : '0px' }}>
                {!isMe && !isFollowUp && (
                  <Text variant="bodySmall" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {msg.sender}
                  </Text>
                )}
                <Box 
                  padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" 
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  background={isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                  style={{ 
                    maxWidth: '80%', 
                    boxShadow: 'var(--ggui-shape-shadow-sm)',
                  }}
                >
                  <Text color={isMe ? 'var(--ggui-color-surface, #ffffff)' : 'var(--ggui-color-onSurface, #18181b)'}>
                    {msg.text}
                  </Text>
                </Box>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </Text>
              </Stack>
            );
          })}
        </Stack>
      </div>

      {/* Input Area */}
      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <form 
          onSubmit={(e) => { e.preventDefault(); state.onSend(); }}
          style={{ display: 'flex', gap: 'var(--ggui-spacing-2, 8px)', alignItems: 'flex-end' }}
        >
          <div style={{ flex: 1 }}>
            <Input 
              label="Chat Message"
              placeholder="Type a message..." 
              value={state.text} 
              onChange={state.setText}
            />
          </div>
          <Button type="submit" variant="primary" disabled={!state.text.trim()} style={{ marginBottom: '4px' }}>
            Send
          </Button>
        </form>
      </Box>
    </div>
  );
}

