// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  }; // Pre-filled profile data for editing (all fields optional)
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    const finalData = {
      ...data,
      completedAt: new Date().toISOString(),
    };
    props.onComplete?.(finalData);
  }, [props.onComplete]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions?.[0] || '👤',
    role: props.initialProfile?.role || '',
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme || 'light',
  });

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isStep1Valid = useMemo(() => {
    return formData.name.trim().length > 0 && emailRegex.test(formData.email);
  }, [formData.name, formData.email]);

  const isStep2Valid = useMemo(() => {
    return formData.role !== '';
  }, [formData.role]);

  const handleUpdateField = useCallback((field: keyof typeof formData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  }, []);

  const nextStep = useCallback(() => {
    setStep(s => Math.min(s + 1, 3));
  }, []);

  const prevStep = useCallback(() => {
    setStep(s => Math.max(s - 1, 1));
  }, []);

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  return {
    step,
    formData,
    isStep1Valid,
    isStep2Valid,
    handleUpdateField,
    nextStep,
    prevStep,
    handleComplete,
    progressValue
  };
}

