import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
  onSubmit?: (data: Record<string, unknown>) => void; // Action: Submit Survey
}

function useComponent(props: Props) {
  const handleSubmit = useCallback((data: Record<string, unknown>) => {
    props.onSubmit?.(data);
  }, [props.onSubmit]);

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    rating: '',
    features: [] as string[],
    comments: '',
  });

  const isValidEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canNext = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && isValidEmail(formData.email);
    if (step === 2) return formData.rating !== '';
    return true;
  }, [step, formData]);

  return { step, setStep, formData, setFormData, handleSubmit, canNext };
}

export default function Component(props: Props) {
  const { step, setStep, formData, setFormData, handleSubmit, canNext } = useComponent(props);

  const updateField = (key: keyof typeof formData, value: any) => setFormData(prev => ({ ...prev, [key]: value }));

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Survey</Heading>
        <Progress value={(step / 4) * 100} showLabel />
        <Text variant="label">{`Step ${step} of 4`}</Text>

        <Card padding={24}>
          {step === 1 && (
            <Stack gap={16}>
              <Input label="Name" required value={formData.name} onChange={(v) => updateField('name', v)} />
              <Input label="Email" required type="email" value={formData.email} onChange={(v) => updateField('email', v)} error={formData.email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email) ? 'Invalid email' : undefined} />
            </Stack>
          )}
          {step === 2 && (
            <RadioGroup label="Satisfaction" options={props.satisfactionLabels.map((l, i) => ({ label: l, value: String(i + 1) }))} value={formData.rating} onChange={(v) => updateField('rating', v)} />
          )}
          {step === 3 && (
            <Stack gap={8}>
              <Text variant="label">Feature Interests</Text>
              {props.featureOptions.map(feat => (
                <Checkbox key={feat} label={feat} checked={formData.features.includes(feat)} onChange={(c) => setFormData(prev => ({ ...prev, features: c ? [...prev.features, feat] : prev.features.filter(f => f !== feat) }))} />
              ))}
            </Stack>
          )}
          {step === 4 && (
            <Stack gap={16}>
              <TextArea label="Comments" maxLength={500} showCount value={formData.comments} onChange={(v) => updateField('comments', v)} />
              <Divider />
              <Heading level={4}>Review</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Rating: {formData.rating}</Text>
              <Text>Features: {formData.features.join(', ')}</Text>
              <Text>Comments: {formData.comments}</Text>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="ghost" disabled={step === 1} onClick={() => setStep(s => s - 1)}>Back</Button>
          {step < 4 ? (
            <Button disabled={!canNext} onClick={() => setStep(s => s + 1)}>Next</Button>
          ) : (
            <Button variant="primary" onClick={() => handleSubmit(formData)}>Submit</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

