// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: { id: string; title: string; priority: string; assignee: string; column: string; dueDate: string }[]; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: { id: string; name: string }[]; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
  onTaskUpdate?: (data: Record<string, unknown>) => void; // Action: Task Updated
}

function useComponent(props: Props) {
  const handleTaskUpdate = useCallback((data: Record<string, unknown>) => {
    props.onTaskUpdate?.(data);
  }, [props.onTaskUpdate]);

  const [tasks, setTasks] = useState(props.tasks || []);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState('medium');

  const moveTask = (taskId: string, targetColumn: string) => {
    const updated = tasks.map(t => t.id === taskId ? { ...t, column: targetColumn } : t);
    setTasks(updated);
    handleTaskUpdate({ type: 'MOVE', taskId, targetColumn });
  };

  const addTask = (column: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '??',
      column,
      dueDate: new Date().toLocaleDateString()
    };
    setTasks([...tasks, newTask]);
    setNewTaskTitle('');
    setIsAdding(null);
    handleTaskUpdate({ type: 'CREATE', task: newTask });
  };

  const summary = useMemo(() => ({
    total: tasks.length,
    done: tasks.filter(t => t.column === 'done').length
  }), [tasks]);

  return { tasks, moveTask, addTask, summary, isAdding, setIsAdding, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority };
}

export default function Component(props: Props) {
  const { tasks, moveTask, addTask, summary, isAdding, setIsAdding, newTaskTitle, setNewTaskTitle, newTaskPriority, setNewTaskPriority } = useComponent(props);

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={16}>
        <Heading level={2}>Project Tasks ({summary.done} / {summary.total} Completed)</Heading>
        <Stack direction="horizontal" gap={16} align="start" wrap={true}>
          {props.columns.map(col => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={8} padding={16} style={{ flex: '1 1 300px' }}>
              <Stack gap={12}>
                <Heading level={5}>{col.name} <Badge variant="default">{tasks.filter(t => t.column === col.id).length}</Badge></Heading>
                {tasks.filter(t => t.column === col.id).map(task => (
                  <Card key={task.id} padding={12} shadow="sm" radius="md">
                    <Stack gap={8}>
                      <Text variant="bodySmall">{task.title}</Text>
                      <Stack direction="horizontal" justify="between" align="center" gap={8}>
                        <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'primary'}>{task.priority}</Badge>
                        <Avatar name={task.assignee} size={24} shape="circle" />
                      </Stack>
                      <Dropdown trigger={<Button size="xs" variant="outline" fullWidth>Move</Button>} options={props.columns.filter(c => c.id !== col.id).map(c => ({ value: c.id, label: c.name }))} onChange={(val) => moveTask(task.id, val)} value={col.id} />
                    </Stack>
                  </Card>
                ))}
                {isAdding === col.id ? (
                  <Stack gap={8}>
                    <Input label="Title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="e.g. Design UI" />
                    <Select label="Priority" value={newTaskPriority} onChange={setNewTaskPriority} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} />
                    <Stack direction="horizontal" gap={8}>
                      <Button size="sm" onClick={() => addTask(col.id)}>Add</Button>
                      <Button size="sm" variant="ghost" onClick={() => setIsAdding(null)}>Cancel</Button>
                    </Stack>
                  </Stack>
                ) : (
                  <Button variant="ghost" size="sm" onClick={() => setIsAdding(col.id)} fullWidth>+ Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

