              gridColumn: el.col, gridRow: el.row, cursor: 'pointer',
              backgroundColor: categoryColors[el.category] || categoryColors.other,
              padding: 'var(--ggui-spacing-2, 8px)', borderRadius: 'var(--ggui-shape-radius-sm, 4px)', textAlign: 'center', color: 'var(--ggui-color-surface, #ffffff)'
            }}>
              <Text size="xs" style={{ color: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}>{el.atomicNumber}</Text>
              <Heading level={5} style={{ color: 'var(--ggui-color-surface, #ffffff)' }}>{el.symbol}</Heading>
            </div>
          ))}
        </Box>

        <Stack direction="horizontal" gap={8} wrap>
          {categories.map(cat => (
            <Badge key={cat} style={{ backgroundColor: categoryColors[cat] || categoryColors.other, color: 'var(--ggui-color-surface, #ffffff)' }}>{cat}</Badge>
          ))}
        </Stack>

        {selectedElement && (
          <Card padding={24}>
            <Heading level={3}>{selectedElement.name}</Heading>
            <Stack gap={8} style={{ marginTop: '16px' }}>
              <Text><strong>Symbol:</strong> {selectedElement.symbol}</Text>
              <Text><strong>Atomic Number:</strong> {selectedElement.atomicNumber}</Text>
              <Text><strong>Atomic Weight:</strong> {selectedElement.atomicWeight}</Text>
              <Text><strong>Category:</strong> {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

