import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id: string; name: string; price: number; currency: string; rating: number; reviewCount: number; stock: number; description: string; specifications: unknown[]; reviews: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
  onAddToCart?: (data: Record<string, unknown>) => void; // Action: Add to Cart
}

function useComponent(props: Props) {
  const handleAddToCart = useCallback((data: Record<string, unknown>) => {
    props.onAddToCart?.(data);
  }, [props.onAddToCart]);

  const [quantity, setQuantity] = useState(1);

  const stockStatus = useMemo(() => {
    if (props.product.stock === 0) return { label: 'Out of Stock', variant: 'error' as const };
    if (props.product.stock <= 5) return { label: 'Low Stock', variant: 'warning' as const };
    return { label: 'In Stock', variant: 'success' as const };
  }, [props.product.stock]);

  const addToCart = useCallback(() => {
    handleAddToCart({ productId: props.product.id, quantity });
  }, [handleAddToCart, props.product.id, quantity]);

  return { quantity, setQuantity, stockStatus, addToCart };
}

export default function Component(props: Props) {
  const { quantity, setQuantity, stockStatus, addToCart } = useComponent(props);

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack direction="horizontal" gap={32} wrap>
        <Box background="var(--ggui-color-surfaceVariant)" borderRadius={12} padding={32} style={{ flex: 1, minWidth: 300, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
          <Text weight="bold" size="4xl" color="var(--ggui-color-onSurfaceVariant)">{props.product.name}</Text>
        </Box>
        <Stack gap={16} style={{ flex: 1, minWidth: 300 }}>
          <Heading level={1}>{props.product.name}</Heading>
          <Text variant="bodyLarge" weight="bold">{props.product.currency}{props.product.price.toFixed(2)}</Text>
          <Badge variant={stockStatus.variant}>{stockStatus.label}</Badge>
          <Stack direction="horizontal" gap={8} align="center">
            <Button size="sm" variant="outline" onClick={() => setQuantity(Math.max(1, quantity - 1))}>-</Button>
            <Text>{quantity}</Text>
            <Button size="sm" variant="outline" onClick={() => setQuantity(Math.min(props.product.stock, quantity + 1))}>+</Button>
            <Button variant="primary" disabled={props.product.stock === 0} onClick={addToCart}>Add to Cart</Button>
          </Stack>
        </Stack>
      </Stack>
      <Spacer size={32} />
      <Tabs items={[
        { key: 'desc', label: 'Description', content: <Text>{props.product.description}</Text> },
        { key: 'specs', label: 'Specifications', content: <Table columns={[{key: 'key', header: 'Key'}, {key: 'value', header: 'Value'}]} data={props.product.specifications as any[]} /> },
        { key: 'reviews', label: 'Reviews', content: <Stack gap={16}>
          {(props.product.reviews as any[]).map((r, i) => (
            <Card key={i} padding={16}>
              <Text weight="semibold">{r.author}</Text>
              <Text>{r.text}</Text>
            </Card>
          ))}
        </Stack> }
      ]} />
    </Container>
  );
}

