import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: { sender: string; text: string; timestamp: string }[]; // Array of messages with sender name, text, and ISO timestamp
  onSendMessage?: (data: Record<string, unknown>) => void; // Action: Send Message
}

function useComponent(props: Props) {
  const handleSendMessage = useCallback((data: Record<string, unknown>) => {
    props.onSendMessage?.(data);
  }, [props.onSendMessage]);

  const [inputValue, setInputValue] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [props.messages]);

  const onSend = useCallback(() => {
    if (!inputValue.trim()) return;
    handleSendMessage({ text: inputValue, timestamp: new Date().toISOString() });
    setInputValue('');
  }, [inputValue, handleSendMessage]);

  return { inputValue, setInputValue, onSend, messagesEndRef };
}

export default function Component(props: Props) {
  const { inputValue, setInputValue, onSend, messagesEndRef } = useComponent(props);

  return (
    <Card padding={0} style={{ display: 'flex', flexDirection: 'column', height: '100%', overflow: 'hidden' }}>
      <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{props.title}</Heading>
          <Badge variant="secondary">{props.participantCount} participants</Badge>
        </Stack>
      </Box>
      <Box style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)' }}>
        <Stack gap={12}>
          {props.messages.map((m, i) => (
            <Box key={i} style={{ alignSelf: m.sender === props.currentUser ? 'flex-end' : 'flex-start', maxWidth: '80%', padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)', borderRadius: 'var(--ggui-shape-radius-md, 8px)', background: m.sender === props.currentUser ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: m.sender === props.currentUser ? 'white' : 'var(--ggui-color-onSurface, #18181b)' }}>
              <Text size="xs" weight="semibold">{m.sender}</Text>
              <Text variant="bodySmall" color="inherit">{m.text}</Text>
              <Text size="xs" style={{ opacity: 0.7, marginTop: '4px' }}>{new Date(m.timestamp).toLocaleTimeString()}</Text>
            </Box>
          ))}
          <div ref={messagesEndRef} />
        </Stack>
      </Box>
      <Box padding={'var(--ggui-spacing-4, 16px)'} style={{ borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)' }}>
        <Stack direction="horizontal" gap={8}>
          <Input label="" placeholder="Type a message..." value={inputValue} onChange={setInputValue} style={{ flex: 1 }} />
          <Button onClick={onSend} disabled={!inputValue.trim()}>Send</Button>
        </Stack>
      </Box>
    </Card>
  );
}

