// ⚠️ DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useEffect, useMemo, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';

// ⚠️ DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
  onComplete?: (data: Record<string, unknown>) => void; // Action: Complete Setup
}

function useComponent(props: Props) {
  const handleComplete = useCallback((data: Record<string, unknown>) => {
    props.onComplete?.(data);
  }, [props.onComplete]);

  const [step, setStep] = useState(1);
  const [profile, setProfile] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || props.avatarOptions[0],
    role: props.initialProfile?.role || props.roleOptions[0],
    emailNotifications: props.initialProfile?.emailNotifications ?? true,
    theme: props.initialProfile?.theme || 'light',
  });

  const isEmailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(profile.email), [profile.email]);
  const canNext = useMemo(() => {
    if (step === 1) return profile.name.trim() !== '' && isEmailValid;
    return true;
  }, [step, profile.name, isEmailValid]);

  return { step, setStep, profile, setProfile, handleComplete, canNext, isEmailValid };
}

export default function Component(props: Props) {
  const { step, setStep, profile, setProfile, handleComplete, canNext, isEmailValid } = useComponent(props);

  return (
    <Container maxWidth="sm" padding={24}>
      <Stack gap={24}>
        <Stack gap={8}>
          <Heading level={2}>Setup Profile {step}/3</Heading>
          <Progress value={(step - 1) * 50} max={100} />
        </Stack>

        {step === 1 && (
          <Stack gap={16}>
            <Input label="Name" value={profile.name} onChange={(v) => setProfile({ ...profile, name: v })} required />
            <Input label="Email" type="email" value={profile.email} onChange={(v) => setProfile({ ...profile, email: v })} error={!isEmailValid && profile.email ? 'Invalid email' : undefined} required />
            <Text variant="label">Select Avatar</Text>
            <Row gap={8}>
              {props.avatarOptions.map(emoji => (
                <Button key={emoji} variant={profile.avatar === emoji ? 'primary' : 'secondary'} onClick={() => setProfile({ ...profile, avatar: emoji })}>{emoji}</Button>
              ))}
            </Row>
          </Stack>
        )}

        {step === 2 && (
          <Stack gap={16}>
            <Select label="Role" value={profile.role} onChange={(v) => setProfile({ ...profile, role: v })} options={props.roleOptions.map(r => ({ value: r, label: r }))} />
            <Toggle label="Email Notifications" checked={profile.emailNotifications} onChange={(v) => setProfile({ ...profile, emailNotifications: v })} />
            <Toggle label="Dark Theme" checked={profile.theme === 'dark'} onChange={(v) => setProfile({ ...profile, theme: v ? 'dark' : 'light' })} />
          </Stack>
        )}

        {step === 3 && (
          <Card padding={16}>
            <Stack gap={12}>
              <Heading level={4}>Review</Heading>
              <Text>Name: {profile.name}</Text>
              <Text>Email: {profile.email}</Text>
              <Text>Avatar: {profile.avatar}</Text>
              <Text>Role: {profile.role}</Text>
              <Text>Notifications: {profile.emailNotifications ? 'On' : 'Off'}</Text>
              <Text>Theme: {profile.theme}</Text>
            </Stack>
          </Card>
        )}

        <Row justify="between">
          <Button 
            variant="ghost" 
            disabled={step === 1} 
            onClick={() => setStep(step - 1)}
          >Back</Button>

          {step < 3 ? (
            <Button 
              disabled={!canNext} 
              onClick={() => setStep(step + 1)}
            >Next</Button>
          ) : (
            <Button 
              variant="primary" 
              onClick={() => handleComplete(profile)}
            >Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
